triple_quicksort_safety.solution:
Lemma triple_quicksort_safety : forall p i n L,
  n = length L ->
  i >= 0 ->
  triple (val_quicksort p i n)
    (hseg L p i)
    (fun _ => \exists L', \[length L' = length L] \* hseg L' p i).
Proof using.
  introv Hn Hi. gen i L. induction_wf IH: (downto 0) n. intros.
  xwp. xapp. xif; intros C.
  { xapp triple_pivot_safety. { math. } { math. }
    intros j L1 x L2 (HL&HJ&HN).
    xapp. xapp. { math. } { math. subst. rew_list. math. }
    intros L1' HL1'. xapp. xapp. xapp.
    { math. } { math. subst. rew_list. math. }
    intros L2' HL2'. xsimpl (L1' ++ x :: L2').
    { rew_list. rewrite HL1', HL2'. subst. rew_list. math. }
    { xchange <- hseg_app. xchange <- hseg_cons. xsimpl. } }
  { xval. xsimpl L. auto. }
Qed.

triple_quicksort.solution:
Lemma triple_quicksort : forall p i n L,
  n = length L ->
  i >= 0 ->
  triple (val_quicksort p i n)
    (hseg L p i)
    (fun _ => \exists L', \[permut L L'] \* \[sorted L'] \* hseg L' p i).
Proof using.
  introv Hn Hi. gen i L. induction_wf IH: (downto 0) n. intros.
  xwp. xapp. xif; intros C.
  { xapp triple_pivot. { math. } { math. }
    intros j L1 x L2 (HL&HJ&HN&HP&HB).
    xapp. xapp. { math. } { math. subst. rew_list. math. }
    intros L1' (HP1&HS1). xapp. xapp. xapp.
    { math. } { math. subst. rew_list. math. }
    intros L2' (HP2&HS2). xsimpl (L1' ++ x :: L2').
    { applys permut_trans HP. applys permut_app. applys HP1.
      applys permut_cons. applys HP2. }
    { applys sorted_app. auto. auto. auto. }
    { xchange <- hseg_app. xchange <- hseg_cons. xsimpl. } }
  { xval. xsimpl L. { applys permut_refl. }
    { destruct L as [|x [|y L']]; try (simpl in C; math).
      { constructor. } { constructor. } } }
Qed.
